#usda 1.0

def Xform "World"
{
    def Mesh "Ground" (
        prepend apiSchemas = ["MaterialBindingAPI"]
    )
    {
        int[] faceVertexCounts = [4]
        int[] faceVertexIndices = [0, 1, 2, 3]
        rel material:binding = </World/Looks/GroundMaterial>
        point3f[] points = [(-5, 0, -5), (5, 0, -5), (5, 0, 5), (-5, 0, 5)]
        double3 xformOp:translate = (0, 0, 0)
        uniform token[] xformOpOrder = ["translate"]
    }

    def Xform "Character"
    {
        double3 xformOp:translate = (0, 1, 0)
        uniform token[] xformOpOrder = ["translate"]

        def Mesh "Body"
        {
            int[] faceVertexCounts = [4, 4, 4, 4, 4, 4]
            int[] faceVertexIndices = [0, 1, 2, 3, 4, 6, 2, 1, 0, 4, 7, 3, 0, 5, 6, 4, 1, 5, 6, 2, 0, 3, 7, 5]
            point3f[] points = [(-0.5, -0.5, -0.5), (0.5, -0.5, -0.5), (0.5, 0.5, -0.5), (-0.5, 0.5, -0.5), (-0.5, -0.5, 0.5), (0.5, -0.5, 0.5), (0.5, 0.5, 0.5), (-0.5, 0.5, 0.5)]
            double3 xformOp:translate = (0, 1, 0)
            uniform token[] xformOpOrder = ["translate"]
        }
    }

    def DomeLight "Light"
    {
        float intensity = 1000
    }

    def Xform "Looks"
    {
        def Material "GroundMaterial"
        {
            def Shader "surface"
            {
                uniform token info:implementationSource = "sourceAsset"
                uniform asset info:sourceAsset = @UsdPreviewSurface@
                color3f inputs:diffuseColor = (0.3, 0.3, 0.3)
            }
        }
    }
}
